class Solution:
	def maxProfit(self, transactions: List[List[int]]) -> int:
		transactions.sort(key=lambda x: (x[1] - x[0]) / x[0], reverse=True)
		maxProfit = 0
		i = 0
		while i < len(transactions):
			if transactions[i][1] - transactions[i][0] > 0:
				maxProfit += transactions[i][1] - transactions[i][0]
				i += 1
			else:
				i += 1
			return maxProfit

def main():
	import sys
	sol = Solution()
	transactions = [[5, 10], [2, 3], [10, 12]]
	print(sol.maxProfit(transactions))

