class Solution {
public:
	int maxProfit(vector<pair<int, int>>& transactions) {
		sort(transactions.begin(), transactions.end(), [](pair<int, int> a, pair<int, int> b) {
			return (double)(a.second - a.first) / a.first > (double)(b.second - b.first) / b.first;
		});
		int maxProfit = 0;
		for (int i = 0; i < transactions.size(); i++) {
			if (transactions[i].second - transactions[i].first > 0) {
				maxProfit += transactions[i].second - transactions[i].first;
			}
		}
		return maxProfit;
	}
};

def main():
	import sys
	sol = Solution()
	transactions = [(5, 10), (2, 3), (10, 12)]
	print(sol.maxProfit(transactions))
